CREATE TABLE IF NOT EXISTS `material_types` (
  `id` int AUTO_INCREMENT NOT NULL,
  `erpCompanyId` int,
  `name` varchar(50) NOT NULL,
  `icon` varchar(10),
  `sortOrder` int NOT NULL DEFAULT 0,
  `createdAt` timestamp NOT NULL DEFAULT (now()),
  `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
  `deletedAt` timestamp,
  CONSTRAINT `material_types_id` PRIMARY KEY(`id`)
);

ALTER TABLE `material_suppliers` ADD COLUMN IF NOT EXISTS `materialTypeId` int;

ALTER TABLE `material_types` ADD CONSTRAINT `material_types_erpCompanyId_erp_companies_id_fk` FOREIGN KEY (`erpCompanyId`) REFERENCES `erp_companies`(`id`) ON DELETE no action ON UPDATE no action;

ALTER TABLE `material_suppliers` ADD CONSTRAINT `material_suppliers_materialTypeId_material_types_id_fk` FOREIGN KEY (`materialTypeId`) REFERENCES `material_types`(`id`) ON DELETE no action ON UPDATE no action;

